/** UsptRsltIdxIemCnHistDao.insert */
insert into uspt_rslt_idx_iem_cn_hist
	(
		rslt_hist_id
		, rslt_idx_iem_id
		, rslt_idx_iem_cn_id
		, rslt_idx_iem_cn
		, creator_id
		, created_dt
	) values (
		#{rsltHistId}
		, #{rsltIdxIemId}
		, #{rsltIdxIemCnId}
		, #{rsltIdxIemCn}
		, #{creatorId}
		, #{createdDt}
	)
